    .ph-gallery-item:nth-child(2) { background: linear-gradient(135deg,#0A2D0A,#1A5C1A); }
    .ph-gallery-item:nth-child(3) { background: linear-gradient(135deg,#2D2D00,#5C5C00); }
    .ph-gallery-item:nth-child(4) { background: linear-gradient(135deg,#2D000A,#5C001A); }
    .ph-gallery-item:nth-child(5) { grid-column: span 2; background: linear-gradient(135deg,#00102D,#00215C); }
    .ph-gallery-item::after {
      content: 'View';
      position:absolute; inset:0;
      background: rgba(212,130,10,0.85);
      display:flex; align-items:center; justify-content:center;
      font-size:1rem; font-weight:700; color:white;
      font-family:'DM Sans',sans-serif; letter-spacing:0.1em;
      opacity:0; transition:opacity 0.3s;
    }
    .ph-gallery-item:hover::after { opacity:1; }

    /* ── TESTIMONIALS ── */
    .ph-testi-wrap { background: white; }
    .ph-testi-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 24px;
    }
    .ph-testi-card {
      background: #FFF9F3;
      border-radius: 28px; padding: 36px;
      border: 1px solid rgba(212,130,10,0.08);
      transition: all 0.3s;
    }
    .ph-testi-card:hover {
      border-color: rgba(212,130,10,0.2);
      box-shadow: 0 16px 50px rgba(212,130,10,0.08);
    }
    .ph-testi-stars { font-size: 1.1rem; margin-bottom: 16px; letter-spacing: 2px; }
    .ph-testi-text {
      font-size: 0.95rem; color: var(--muted);
      line-height: 1.8; margin-bottom: 24px; font-style: italic;
    }
    .ph-testi-author { display: flex; align-items: center; gap: 14px; }
    .ph-testi-avatar {
      width: 48px; height: 48px; border-radius: 50%;
      background: linear-gradient(135deg, var(--amber), var(--terra));
      display: flex; align-items: center; justify-content: center;
      font-size: 1.3rem; font-weight: 700; color: white;
      font-family: 'Playfair Display', serif;
    }
    .ph-testi-name { font-weight: 600; color: var(--brown); font-size: 0.95rem; }
    .ph-testi-city { font-size: 0.78rem; color: var(--muted); }

    /* ── CONTACT ── */
    .ph-contact-wrap { background: var(--cream); }
    .ph-contact-grid {
      max-width: 1300px; margin: 0 auto;
      padding: 100px 60px;
      display: grid;
      grid-template-columns: 1fr 1.2fr;
      gap: 80px; align-items: start;
    }
    .ph-contact-info-item {
      display: flex; gap: 18px; margin-bottom: 32px;
    }
    .ph-contact-icon {
      width: 52px; height: 52px; flex-shrink: 0;
      background: linear-gradient(135deg, var(--amber), #B8720A);
      border-radius: 16px;
      display: flex; align-items: center; justify-content: center;
      font-size: 1.3rem;
      box-shadow: 0 8px 20px rgba(212,130,10,0.25);
    }
    .ph-contact-info-title { font-weight: 600; color: var(--brown); margin-bottom: 4px; }
    .ph-contact-info-text { font-size: 0.9rem; color: var(--muted); line-height: 1.6; }

    .ph-form {
      background: white; border-radius: 32px;
      padding: 48px; box-shadow: 0 20px 60px rgba(61,31,0,0.08);
    }
    .ph-form-title {
      font-family: 'Playfair Display', serif;
      font-size: 1.8rem; font-weight: 700;
      color: var(--brown); margin-bottom: 8px;
    }
    .ph-form-sub { color: var(--muted); font-size: 0.9rem; margin-bottom: 32px; }
    .ph-input {
      width: 100%;
      padding: 14px 20px;
      border: 1.5px solid rgba(61,31,0,0.12);
      border-radius: 14px;
      font-family: 'DM Sans', sans-serif;
      font-size: 0.95rem; color: var(--brown);
      background: var(--cream);
      margin-bottom: 16px;
      transition: border-color 0.2s;
      outline: none;
    }
    .ph-input:focus { border-color: var(--amber); }
    .ph-input::placeholder { color: var(--muted); }
    .ph-textarea { height: 120px; resize: vertical; }
    .ph-submit {
      width: 100%;
      padding: 16px;
      background: var(--brown); color: white;
      border: none; border-radius: 14px;
      font-family: 'DM Sans', sans-serif;
      font-size: 1rem; font-weight: 600;
      cursor: pointer; transition: all 0.3s;
      margin-top: 8px;
    }
    .ph-submit:hover { background: var(--amber); transform: translateY(-2px); }
    .ph-submit:disabled { opacity: 0.7; cursor: not-allowed; }

    .ph-success-msg {
      background: rgba(122,158,126,0.15);
      border: 1px solid rgba(122,158,126,0.4);
      color: #3A7A3A; border-radius: 12px;
      padding: 14px 20px; font-size: 0.9rem;
      margin-bottom: 16px; display: flex; gap: 10px;
    }

    /* ── CTA ── */
    .ph-cta-wrap {
      background: linear-gradient(135deg, var(--amber) 0%, #9A5E00 100%);
      padding: 100px 60px; text-align: center;
      position: relative; overflow: hidden;
    }
    .ph-cta-wrap::before {
      content:'🐾';
      position:absolute; font-size:24rem;
      opacity:0.06; top:-60px; right:-60px;
      line-height:1;
    }
    .ph-cta-title {
      font-family: 'Playfair Display', serif;
      font-size: clamp(2.5rem, 4vw, 3.8rem);
      font-weight: 900; color: white;
      margin-bottom: 20px; position: relative;
    }
    .ph-cta-sub {
      color: rgba(255,255,255,0.8);
      font-size: 1.1rem; max-width: 540px;
      margin: 0 auto 44px; line-height: 1.7;
    }
    .ph-cta-btns { display: flex; gap: 16px; justify-content: center; flex-wrap: wrap; }
    .ph-btn-white {
      padding: 16px 40px;
      background: white; color: var(--amber);
      border: none; border-radius: 50px;
      font-family: 'DM Sans', sans-serif;
      font-size: 1rem; font-weight: 700;
      cursor: pointer; text-decoration: none;
      transition: all 0.3s;
      box-shadow: 0 8px 30px rgba(0,0,0,0.15);
      display: inline-block;
    }
    .ph-btn-white:hover {
      transform: translateY(-3px);
      box-shadow: 0 16px 50px rgba(0,0,0,0.2);
      color: var(--brown); text-decoration: none;
    }
    .ph-btn-outline-white {
      padding: 16px 40px;
      background: transparent; color: white;
      border: 2px solid rgba(255,255,255,0.5);
      border-radius: 50px;
      font-family: 'DM Sans', sans-serif;
      font-size: 1rem; font-weight: 500;
      cursor: pointer; text-decoration: none;
      transition: all 0.3s;
      display: inline-block;
    }
    .ph-btn-outline-white:hover {
      border-color: white; background: rgba(255,255,255,0.1);
      color: white; text-decoration: none;
    }

    /* ── REVEAL ANIMATIONS ── */
    .reveal {
      opacity: 0; transform: translateY(32px);
      transition: opacity 0.7s ease, transform 0.7s ease;
    }
    .reveal.visible { opacity: 1; transform: none; }

    @keyframes fadeUp {
      from { opacity:0; transform:translateY(24px); }
      to   { opacity:1; transform:none; }
    }

