import axios from "axios";
import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import Nav from "./Nev";

const API = "http://localhost/Petshop";

function Home() {
  const [uname, setusername] = useState("");
  const [email, setemail] = useState("");
  const [message, setmessage] = useState("");
  const [mobile, setmobile] = useState("");
  const [products, setProducts] = useState([]);
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const navigate = useNavigate();
  const heroRef = useRef(null);

  // ── Fetch products from your existing show.php ──
  useEffect(() => {
    axios.get(`${API}/show.php`)
      .then(res => setProducts(res.data || []))
      .catch(() => setProducts([]));
  }, []);

  // ── Scroll reveal ──
  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add("visible");
          observer.unobserve(e.target);
        }
      }),
      { threshold: 0.12 }
    );
    document.querySelectorAll(".reveal").forEach(el => observer.observe(el));
    return () => observer.disconnect();
  }, [products]);

  // ── Parallax hero ──
  useEffect(() => {
    const handleScroll = () => {
      if (heroRef.current) {
        heroRef.current.style.setProperty("--scroll", `${window.scrollY * 0.35}px`);
      }
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  function handleForm(e) {
    e.preventDefault();
    setSending(true);
    const data = { name: uname, email, mobile, message };
    axios({
      method: "post",
      url: `${API}/contact.php`,
      data,
      headers: { "Content-Type": "multipart/form-data" },
    }).then(() => {
      setSending(false);
      setSent(true);
      setTimeout(() => setSent(false), 4000);
      navigate(0);
    }).catch(() => setSending(false));
  }

  // pet emoji by name
  const petEmoji = (name = "") => {
    const n = name.toLowerCase();
    if (n.includes("cat") || n.includes("persian")) return "🐈";
    if (n.includes("bird") || n.includes("parrot")) return "🦜";
    if (n.includes("fish") || n.includes("aqua")) return "🐠";
    return "🐕";
  };

  const gradients = [
    "linear-gradient(135deg,#FFF3E0,#FFE0B2)",
    "linear-gradient(135deg,#E8F5E9,#C8E6C9)",
    "linear-gradient(135deg,#FFF8E1,#FFECB3)",
    "linear-gradient(135deg,#FCE4EC,#F8BBD0)",
    "linear-gradient(135deg,#E3F2FD,#BBDEFB)",
    "linear-gradient(135deg,#F3E5F5,#E1BEE7)",
  ];

  const badges = ["Popular","New Arrival","","Premium","","Featured"];

  const styles = `
    @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;0,900;1,700&family=DM+Sans:wght@300;400;500;600&display=swap');

    :root {
      --cream: #FDF6ED;
      --brown: #3D1F00;
      --amber: #D4820A;
      --amber-l: #F5A623;
      --terra: #C15B3A;
      --sage: #7A9E7E;
      --muted: #8A6F55;
      --dark: #1A0F00;
      --white: #ffffff;
      --card-radius: 28px;
      --scroll: 0px;
    }

    * { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: 'DM Sans', sans-serif;
      background: var(--cream);
      color: var(--brown);
      overflow-x: hidden;
    }

    /* ── HERO ── */
    .ph-hero {
      min-height: 100vh;
      position: relative;
      display: flex;
      align-items: center;
      overflow: hidden;
      background: var(--dark);
    }

    .ph-hero-bg {
      position: absolute; inset: 0;
      background: linear-gradient(135deg, #0D0600 0%, #2D1200 45%, #1A0A00 100%);
      transform: translateY(var(--scroll));
      will-change: transform;
    }

    .ph-hero-orbs {
      position: absolute; inset: 0; pointer-events: none;
    }
    .ph-orb {
      position: absolute; border-radius: 50%;
      filter: blur(80px); opacity: 0.35;
    }
    .ph-orb-1 {
      width: 600px; height: 600px;
      background: radial-gradient(circle, #D4820A, transparent 70%);
      top: -150px; right: -100px;
      animation: orbFloat 8s ease-in-out infinite;
    }
    .ph-orb-2 {
      width: 400px; height: 400px;
      background: radial-gradient(circle, #7A9E7E, transparent 70%);
      bottom: -100px; left: -50px;
      animation: orbFloat 10s ease-in-out infinite reverse;
    }
    .ph-orb-3 {
      width: 300px; height: 300px;
      background: radial-gradient(circle, #C15B3A, transparent 70%);
      top: 40%; left: 35%;
      animation: orbFloat 12s ease-in-out infinite 3s;
    }

    @keyframes orbFloat {
      0%,100% { transform: translate(0,0) scale(1); }
      33% { transform: translate(30px,-20px) scale(1.1); }
      66% { transform: translate(-20px,15px) scale(0.95); }
    }

    .ph-hero-content {
      position: relative; z-index: 2;
      width: 100%; max-width: 1300px;
      margin: 0 auto;
      padding: 120px 60px 80px;
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 60px;
      align-items: center;
    }

    .ph-hero-badge {
      display: inline-flex; align-items: center; gap: 8px;
      background: rgba(212,130,10,0.15);
      border: 1px solid rgba(212,130,10,0.4);
      border-radius: 50px; padding: 6px 18px;
      font-size: 0.78rem; font-weight: 600;
      letter-spacing: 0.12em; text-transform: uppercase;
      color: var(--amber-l);
      margin-bottom: 28px;
      animation: fadeUp 0.7s ease both;
    }
    .ph-dot {
      width: 7px; height: 7px;
      background: var(--amber-l); border-radius: 50%;
      animation: blink 1.5s infinite;
    }
    @keyframes blink { 0%,100%{opacity:1}50%{opacity:0.2} }

    .ph-hero-title {
      font-family: 'Playfair Display', serif;
      font-size: clamp(3rem, 5.5vw, 6rem);
      line-height: 1.0;
      font-weight: 900;
      color: var(--white);
      margin-bottom: 28px;
      animation: fadeUp 0.7s 0.1s ease both;
    }
    .ph-hero-title em {
      font-style: italic;
      color: var(--amber-l);
      position: relative;
      display: inline-block;
    }
    .ph-hero-title em::after {
      content: '';
      position: absolute;
      bottom: 6px; left: 0; right: 0;
      height: 3px;
      background: linear-gradient(90deg, var(--amber-l), transparent);
      border-radius: 2px;
    }

    .ph-hero-sub {
      font-size: 1.1rem;
      color: rgba(255,255,255,0.6);
      line-height: 1.8;
      max-width: 480px;
      margin-bottom: 44px;
      font-weight: 300;
      animation: fadeUp 0.7s 0.2s ease both;
    }

    .ph-hero-btns {
      display: flex; gap: 16px;
      animation: fadeUp 0.7s 0.3s ease both;
      flex-wrap: wrap;
    }

    .ph-btn-primary {
      padding: 16px 36px;
      background: var(--amber);
      color: var(--white);
      border: none; border-radius: 50px;
      font-family: 'DM Sans', sans-serif;
      font-size: 1rem; font-weight: 600;
      cursor: pointer; text-decoration: none;
      transition: all 0.3s;
      box-shadow: 0 8px 30px rgba(212,130,10,0.35);
      display: inline-flex; align-items: center; gap: 10px;
    }
    .ph-btn-primary:hover {
      background: #B8720A;
      transform: translateY(-3px);
      box-shadow: 0 14px 40px rgba(212,130,10,0.45);
      color: white; text-decoration: none;
    }

    .ph-btn-ghost {
      padding: 16px 36px;
      background: transparent;
      color: rgba(255,255,255,0.85);
      border: 1.5px solid rgba(255,255,255,0.25);
      border-radius: 50px;
      font-family: 'DM Sans', sans-serif;
      font-size: 1rem; font-weight: 500;
      cursor: pointer; text-decoration: none;
      transition: all 0.3s;
    }
    .ph-btn-ghost:hover {
      border-color: var(--amber-l);
      color: var(--amber-l);
      text-decoration: none;
    }

    .ph-hero-stats {
      display: flex; gap: 44px;
      margin-top: 56px;
      padding-top: 40px;
      border-top: 1px solid rgba(255,255,255,0.08);
      animation: fadeUp 0.7s 0.4s ease both;
    }
    .ph-stat-num {
      font-family: 'Playfair Display', serif;
      font-size: 2.2rem; font-weight: 700;
      color: var(--amber-l);
    }
    .ph-stat-label {
      font-size: 0.78rem; font-weight: 500;
      color: rgba(255,255,255,0.4);
      text-transform: uppercase; letter-spacing: 0.1em;
      margin-top: 2px;
    }

    /* ── HERO VISUAL SIDE ── */
    .ph-hero-visual {
      position: relative;
      display: flex; justify-content: center;
      animation: fadeLeft 0.9s 0.2s ease both;
    }

    @keyframes fadeLeft {
      from { opacity:0; transform: translateX(50px); }
      to   { opacity:1; transform: translateX(0); }
    }

    .ph-main-card {
      width: 380px; height: 480px;
      background: linear-gradient(145deg, #2A1200, #4A2000);
      border-radius: 40px;
      position: relative; overflow: hidden;
      box-shadow: 0 40px 100px rgba(0,0,0,0.5), 0 0 0 1px rgba(212,130,10,0.15);
    }
    .ph-main-card::before {
      content:'';
      position:absolute; inset:0;
      background: linear-gradient(135deg, rgba(212,130,10,0.1), transparent 50%);
    }

    .ph-main-pet {
      position: absolute;
      top: 50%; left: 50%;
      transform: translate(-50%, -55%);
      font-size: 9rem;
      animation: petFloat 4s ease-in-out infinite;
      filter: drop-shadow(0 20px 40px rgba(0,0,0,0.4));
      line-height: 1;
    }
    @keyframes petFloat {
      0%,100%{ transform: translate(-50%,-55%); }
      50%{ transform: translate(-50%,-60%); }
    }

    .ph-card-info {
      position: absolute; bottom: 0; left: 0; right: 0;
      padding: 28px;
      background: linear-gradient(to top, rgba(0,0,0,0.8) 0%, transparent 100%);
    }
    .ph-card-badge {
      display: inline-block;
      background: var(--amber); color: white;
      padding: 4px 14px; border-radius: 20px;
      font-size: 0.72rem; font-weight: 700;
      letter-spacing: 0.06em; margin-bottom: 8px;
    }
    .ph-card-name {
      font-family: 'Playfair Display', serif;
      font-size: 1.5rem; font-weight: 700;
      color: white;
    }
    .ph-card-price { color: rgba(255,255,255,0.6); font-size: 0.95rem; margin-top: 2px; }

    .ph-float-pill {
      position: absolute;
      background: rgba(255,255,255,0.95);
      backdrop-filter: blur(12px);
      border-radius: 20px;
      padding: 14px 20px;
      box-shadow: 0 16px 50px rgba(0,0,0,0.2);
      animation: floatPill 4s ease-in-out infinite;
    }
    .ph-float-pill:nth-child(2) { top: -10px; right: -30px; animation-delay: 0s; }
    .ph-float-pill:nth-child(3) { bottom: 80px; left: -40px; animation-delay: -2s; }
    @keyframes floatPill {
      0%,100%{ transform: translateY(0); }
      50%{ transform: translateY(-10px); }
    }
    .ph-pill-icon { font-size: 1.4rem; }
    .ph-pill-text { font-size: 0.7rem; color: var(--muted); margin-top: 2px; }
    .ph-pill-val { font-size: 0.9rem; font-weight: 700; color: var(--brown); }

    /* ── TRUST BAR ── */
    .ph-trust {
      background: var(--brown);
      padding: 32px 60px;
      display: flex; justify-content: center;
      gap: 60px; flex-wrap: wrap;
    }
    .ph-trust-item {
      display: flex; align-items: center; gap: 14px;
      color: rgba(255,255,255,0.7);
    }
    .ph-trust-icon {
      font-size: 1.8rem;
      width: 52px; height: 52px;
      background: rgba(212,130,10,0.2);
      border-radius: 14px;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
    }
    .ph-trust-title { font-weight: 600; color: white; font-size: 0.95rem; }
    .ph-trust-sub { font-size: 0.78rem; color: rgba(255,255,255,0.45); margin-top: 2px; }

    /* ── SECTIONS ── */
    .ph-section {
      max-width: 1300px; margin: 0 auto;
      padding: 100px 60px;
    }
    .ph-section-full { padding: 100px 0; }

    .ph-label {
      font-size: 0.78rem; font-weight: 600;
      letter-spacing: 0.16em; text-transform: uppercase;
      color: var(--amber); margin-bottom: 10px;
    }
    .ph-title {
      font-family: 'Playfair Display', serif;
      font-size: clamp(2rem, 3.5vw, 3rem);
      font-weight: 700; line-height: 1.15;
      color: var(--brown);
    }
    .ph-title-light { color: white; }
    .ph-section-header {
      display: flex; justify-content: space-between;
      align-items: flex-end; margin-bottom: 56px;
      gap: 20px; flex-wrap: wrap;
    }

    /* ── CATEGORIES ── */
    .ph-cats-wrap {
      background: var(--dark);
      padding: 100px 60px;
    }
    .ph-cats-grid {
      max-width: 1300px; margin: 0 auto;
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 20px;
    }
    .ph-cat-card {
      background: rgba(255,255,255,0.04);
      border: 1px solid rgba(255,255,255,0.08);
      border-radius: 28px;
      padding: 40px 28px;
      text-align: center;
      cursor: pointer;
      text-decoration: none;
      transition: all 0.35s;
      position: relative; overflow: hidden;
      display: block;
    }
    .ph-cat-card::before {
      content:'';
      position:absolute; inset:0;
      background: linear-gradient(135deg, rgba(212,130,10,0.15), transparent);
      opacity:0; transition: opacity 0.3s;
    }
    .ph-cat-card:hover::before { opacity:1; }
    .ph-cat-card:hover {
      transform: translateY(-10px);
      border-color: rgba(212,130,10,0.4);
      box-shadow: 0 24px 60px rgba(0,0,0,0.4);
      text-decoration: none;
    }
    .ph-cat-emoji {
      font-size: 3.5rem; display: block;
      margin-bottom: 18px;
      transition: transform 0.3s;
    }
    .ph-cat-card:hover .ph-cat-emoji { transform: scale(1.2) rotate(-8deg); }
    .ph-cat-name {
      font-family: 'Playfair Display', serif;
      font-size: 1.2rem; font-weight: 700;
      color: white; margin-bottom: 6px;
    }
    .ph-cat-count { font-size: 0.8rem; color: rgba(255,255,255,0.35); }

    /* ── PRODUCTS GRID ── */
    .ph-products-bg { background: #FFF9F3; }
    .ph-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 28px;
    }
    .ph-card {
      background: white;
      border-radius: var(--card-radius);
      overflow: hidden;
      transition: all 0.35s;
      box-shadow: 0 4px 24px rgba(61,31,0,0.06);
    }
    .ph-card:hover {
      transform: translateY(-12px);
      box-shadow: 0 28px 70px rgba(61,31,0,0.14);
    }
    .ph-card-img {
      height: 220px;
      display: flex; align-items: center; justify-content: center;
      font-size: 5.5rem;
      position: relative; overflow: hidden;
    }
    .ph-card-lbl {
      position: absolute; top: 16px; left: 16px;
      background: var(--terra); color: white;
      font-size: 0.7rem; font-weight: 700;
      padding: 4px 12px; border-radius: 20px;
      text-transform: uppercase; letter-spacing: 0.05em;
    }
    .ph-card-wish {
      position: absolute; top: 14px; right: 14px;
