                <div style={{fontFamily:"Playfair Display,serif",fontSize:"1.1rem",color:"#3D1F00",marginBottom:8}}>
                  More Pets Coming
                </div>
                <NavLink to="product" style={{color:"#D4820A",fontSize:"0.9rem",textDecoration:"none"}}>
