      <div className="ph-about-wrap">
        <div className="ph-about-grid">
          <div className="ph-about-img-box reveal">
            <div className="ph-about-img-main">🐶</div>
            <div className="ph-about-badge-box">
              <div className="ph-about-years">5+</div>
              <div className="ph-about-years-label">Years of Trust</div>
            </div>
          </div>
          <div className="reveal">
            <div className="ph-label">Our Story</div>
            <h2 className="ph-about-title">
              More Than a Pet Shop —<br/>A Family for Your Family
            </h2>
            <p className="ph-about-text">
              Petology started with one simple belief: every pet deserves a loving home, 
              and every family deserves a healthy, happy companion. We work directly with 
              responsible breeders across India to bring you certified, well-cared-for pets 
              — never from puppy mills.
            </p>
            <div className="ph-about-points">
              {[
                "All pets are vet-examined and vaccinated before going home",
                "KCI/CFAB pedigree registration for all purebred animals",
                "Pan-India safe delivery with temperature-controlled transport",
                "Post-purchase support — we're with you for your pet's whole life"
              ].map((point,i)=>(
                <div className="ph-about-point" key={i}>
                  <div className="ph-about-check">✓</div>
                  <div className="ph-about-point-text">{point}</div>
                </div>
              ))}
            </div>
            <NavLink className="ph-btn-primary" to="product" style={{display:"inline-flex"}}>
              Meet Our Pets 🐕
            </NavLink>
          </div>
        </div>
      </div>

      {/* ═══════════ SERVICES ═══════════ */}
      <div className="ph-services-bg">
        <div className="ph-section">
          <div className="ph-section-header">
            <div>
              <div className="ph-label">What We Offer</div>
              <h2 className="ph-title">Our Services</h2>
            </div>
          </div>
          <div className="ph-services-grid">
            {[
              {icon:"🏥",title:"Pet Health Clinic",text:"In-house veterinary consultations, vaccination drives, and health check-ups by certified vets — because prevention is the best care."},
              {icon:"🏨",title:"Pet Hotel & Boarding",text:"Safe, comfortable boarding for your pets when you travel. 24/7 supervision, proper nutrition, and daily exercise routines."},
              {icon:"🚨",title:"Emergency Care",text:"Round-the-clock emergency support line. If your pet needs urgent attention, our vet team is just a call away — always."},
              {icon:"✂️",title:"Grooming Studio",text:"Professional grooming, spa baths, nail trimming, and breed-specific styling. Your pet will look — and feel — their absolute best."},
              {icon:"🎓",title:"Pet Training",text:"Expert trainers who use positive reinforcement to shape good behavior. Puppy basics to advanced obedience — we cover it all."},
              {icon:"🛒",title:"Pet Accessories",text:"Premium food, toys, beds, leashes, and grooming kits. Everything your pet needs, from top brands, all in one place."},
            ].map((s,i)=>(
              <div className="ph-service-card reveal" key={i}>
                <div className="ph-service-icon">{s.icon}</div>
                <div className="ph-service-title">{s.title}</div>
                <p className="ph-service-text">{s.text}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ═══════════ GALLERY ═══════════ */}
      <div className="ph-gallery-wrap">
        <div style={{maxWidth:1300,margin:"0 auto"}}>
          <div className="ph-label" style={{color:"#F5A623"}}>Our Gallery</div>
          <h2 className="ph-title ph-title-light">Our Happy Pets</h2>
        </div>
        <div className="ph-gallery-grid reveal">
          {["🐕","🐈","🦜","🐠","🐩"].map((e,i)=>(
            <div className="ph-gallery-item" key={i}>{e}</div>
          ))}
        </div>
      </div>

      {/* ═══════════ TESTIMONIALS ═══════════ */}
      <div className="ph-testi-wrap">
        <div className="ph-section">
          <div className="ph-section-header">
            <div>
              <div className="ph-label">Happy Customers</div>
              <h2 className="ph-title">What Families Say</h2>
            </div>
          </div>
          <div className="ph-testi-grid">
            {[
              {name:"Priya Sharma", city:"Mumbai", init:"P", rating:"⭐⭐⭐⭐⭐",
                text:"We got our Golden Retriever from Petology last year — the entire process was seamless. The pup arrived healthy, vaccinated, and full of energy. The team even followed up a week later!"},
              {name:"Rahul Mehta", city:"Ahmedabad", init:"R", rating:"⭐⭐⭐⭐⭐",
                text:"Best pet store experience by far. The staff guided us through choosing the right breed for our apartment lifestyle. Our Shih Tzu is an absolute delight — and perfectly adapted to our home."},
              {name:"Anjali Patel", city:"Surat", init:"A", rating:"⭐⭐⭐⭐⭐",
                text:"The grooming service is exceptional. My Persian cat gets treated like royalty every visit. The vets here are genuinely knowledgeable and caring — you can feel they love animals."},
            ].map((t,i)=>(
              <div className="ph-testi-card reveal" key={i}>
                <div className="ph-testi-stars">{t.rating}</div>
                <p className="ph-testi-text">"{t.text}"</p>
                <div className="ph-testi-author">
                  <div className="ph-testi-avatar">{t.init}</div>
                  <div>
                    <div className="ph-testi-name">{t.name}</div>
                    <div className="ph-testi-city">{t.city}</div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ═══════════ CTA ═══════════ */}
      <div className="ph-cta-wrap">
        <h2 className="ph-cta-title">Ready to Find Your Furry Friend?</h2>
        <p className="ph-cta-sub">
          Join 2,000+ Indian families who found their perfect companion through Petology. 
          Create a free account and start browsing today.
