        <div className="ph-cta-btns">
          <NavLink className="ph-btn-white" to="product">Browse Pets 🐾</NavLink>
          <NavLink className="ph-btn-outline-white" to="contact">Talk to Us</NavLink>
        </div>
      </div>

      {/* ═══════════ CONTACT ═══════════ */}
      <div className="ph-contact-wrap">
        <div className="ph-contact-grid">
          <div className="reveal">
            <div className="ph-label">Get in Touch</div>
            <h2 className="ph-title" style={{marginBottom:36}}>We'd Love to Hear From You</h2>
            {[
              {icon:"📍", title:"Visit Us", text:"Shop No. 12, Pet Paradise Complex\nRing Road, Surat, Gujarat — 395007"},
              {icon:"📞", title:"Call Us", text:"+91 98765 43210\nMon–Sat, 9:00 AM – 7:00 PM"},
              {icon:"✉️", title:"Email Us", text:"hello@petology.in\nReply within 24 hours"},
            ].map((c,i)=>(
              <div className="ph-contact-info-item" key={i}>
                <div className="ph-contact-icon">{c.icon}</div>
                <div>
                  <div className="ph-contact-info-title">{c.title}</div>
                  <div className="ph-contact-info-text" style={{whiteSpace:"pre-line"}}>{c.text}</div>
                </div>
              </div>
            ))}
          </div>

          <div className="ph-form reveal">
            <div className="ph-form-title">Send a Message</div>
            <p className="ph-form-sub">We'll get back to you within 24 hours.</p>

            {sent && (
              <div className="ph-success-msg">
                ✅ Thank you! We'll contact you soon.
              </div>
            )}

            <form onSubmit={handleForm}>
              <input className="ph-input" type="text" placeholder="Your Name *"
                onChange={e=>setusername(e.target.value)} required />
              <input className="ph-input" type="tel" placeholder="Phone Number *"
                onChange={e=>setmobile(e.target.value)} required />
              <input className="ph-input" type="email" placeholder="Email Address *"
                onChange={e=>setemail(e.target.value)} required />
              <textarea className="ph-input ph-textarea" placeholder="Your Message..."
                onChange={e=>setmessage(e.target.value)} />
              <button className="ph-submit" type="submit" disabled={sending}>
                {sending ? "Sending..." : "Send Message →"}
              </button>
            </form>
          </div>
        </div>
      </div>

    </>
  );
}

export default Home;
